#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-12

# ============================================================================
# CC Version Floor Consistency
# ============================================================================
# Asserts every derived declaration of the CC supported floor agrees with the
# single source of truth in shared/cc-support.json.
#
# Derived files checked:
#   - src/hooks/src/lib/cc-version-matrix.ts   (MIN_CC_VERSION constant)
#   - CLAUDE.md                                (Version section)
#   - src/skills/doctor/references/version-compatibility.md (overview)
#
# Failure mode caught: someone bumps cc-support.json but forgets to run
# scripts/stamp-cc-support.mjs (or edits a derived file manually), leaving
# users running CC < floor silently bypassing feature gates.
#
# Issue: #1765 (M137)
# ============================================================================
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$SCRIPT_DIR/../.." && pwd)}"

if [[ -t 1 ]]; then
    RED='\033[0;31m'; GREEN='\033[0;32m'; NC='\033[0m'
else
    RED=''; GREEN=''; NC=''
fi

PASS=0
FAIL=0
log_pass() { echo -e "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo -e "  ${RED}✗${NC} $1 — $2"; FAIL=$((FAIL + 1)); }

echo "CC Version Floor Consistency (M137 #1765)"
echo "========================================="

SUPPORT_JSON="$PROJECT_ROOT/shared/cc-support.json"
if [[ ! -f "$SUPPORT_JSON" ]]; then
    log_fail "shared/cc-support.json" "missing"
    exit 1
fi

SOT=$(node -e "console.log(JSON.parse(require('fs').readFileSync('$SUPPORT_JSON','utf8')).supported_floor)")
if ! [[ "$SOT" =~ ^[0-9]+\.[0-9]+\.[0-9]+$ ]]; then
    log_fail "shared/cc-support.json supported_floor" "not a semver: '$SOT'"
    exit 1
fi
log_pass "SoT supported_floor = $SOT"

# 1. src/hooks/src/lib/cc-version-matrix.ts :: MIN_CC_VERSION
MATRIX_VAL=$(grep -E "export const MIN_CC_VERSION = '" "$PROJECT_ROOT/src/hooks/src/lib/cc-version-matrix.ts" | head -1 | sed -E "s/.*'([0-9.]+)'.*/\1/")
if [[ "$MATRIX_VAL" == "$SOT" ]]; then
    log_pass "cc-version-matrix.ts MIN_CC_VERSION = $MATRIX_VAL"
else
    log_fail "cc-version-matrix.ts MIN_CC_VERSION" "got '$MATRIX_VAL', want '$SOT' (run: node scripts/stamp-cc-support.mjs)"
fi

# 2. CLAUDE.md :: Version section
CLAUDE_VAL=$(grep -E "^\- \*\*Current\*\*:.*\*\*Claude Code\*\*: >= " "$PROJECT_ROOT/CLAUDE.md" | head -1 | sed -E "s/.*>= ([0-9.]+).*/\1/")
if [[ "$CLAUDE_VAL" == "$SOT" ]]; then
    log_pass "CLAUDE.md Claude Code floor = $CLAUDE_VAL"
else
    log_fail "CLAUDE.md Claude Code floor" "got '$CLAUDE_VAL', want '$SOT' (run: node scripts/stamp-cc-support.mjs)"
fi

# 3. doctor version-compatibility.md :: overview line (may be absent)
# Read the file first into a variable, then grep that variable. This avoids
# pipefail-aborting on the no-match case where grep exits 1, which the script
# would otherwise treat as a hard fail.
DOCTOR_MD="$PROJECT_ROOT/src/skills/doctor/references/version-compatibility.md"
if [[ -f "$DOCTOR_MD" ]]; then
    DOCTOR_CONTENT=$(cat "$DOCTOR_MD")
    if [[ "$DOCTOR_CONTENT" =~ Minimum\ supported\ CC\ version:\ \*\*([0-9]+\.[0-9]+\.[0-9]+)\*\* ]]; then
        DOCTOR_VAL="${BASH_REMATCH[1]}"
        if [[ "$DOCTOR_VAL" == "$SOT" ]]; then
            log_pass "doctor version-compatibility.md = $DOCTOR_VAL"
        else
            log_fail "doctor version-compatibility.md" "got '$DOCTOR_VAL', want '$SOT'"
        fi
    else
        log_pass "doctor version-compatibility.md (overview-line marker absent, skipping)"
    fi
fi

# 4. Idempotence: stamper should produce zero mutations on an already-stamped tree.
set +e
STAMP_OUT=$(node "$PROJECT_ROOT/scripts/stamp-cc-support.mjs" 2>&1)
STAMP_RC=$?
set -e
if [[ $STAMP_RC -ne 0 ]]; then
    log_fail "stamp-cc-support.mjs" "exited rc=$STAMP_RC — $STAMP_OUT"
elif echo "$STAMP_OUT" | grep -qE "^stamp-cc-support: 0 mutation"; then
    log_pass "stamp-cc-support.mjs is idempotent (no pending mutations)"
elif echo "$STAMP_OUT" | grep -qE "mutation\(s\) applied"; then
    MUT_COUNT=$(echo "$STAMP_OUT" | grep -oE "[0-9]+ mutation" | head -1 | grep -oE "[0-9]+")
    log_fail "stamper not idempotent" "$MUT_COUNT pending mutation(s); commit + re-run"
else
    log_pass "stamp-cc-support.mjs ran (no mutation summary in output; fallback OK)"
fi

echo ""
echo "Results: $PASS passed, $FAIL failed"
[[ $FAIL -eq 0 ]] || exit 1
